const fs=require('fs'); const p=process.env.HOME+'/.openclaw/openclaw.json'; const c=JSON.parse(fs.readFileSync(p,'utf8'));
function redact(v){ if(typeof v==='string' && v.length>12) return v.slice(0,4)+'…'+v.slice(-4); return v }
console.log(JSON.stringify({
 defaultModel:c.agents?.defaults?.model,
 models:Object.keys(c.agents?.defaults?.models||{}),
 providers:Object.fromEntries(Object.entries(c.providers||{}).map(([k,v])=>[k,{baseURL:v.baseURL||v.baseUrl||v.apiBase||v.api_base, apiKey:redact(v.apiKey||v.api_key||v.key||''), models:v.models?Object.keys(v.models):undefined}]))
},null,2));
