arguments.command:
set -euo pipefail
CFG="$HOME/.openclaw/openclaw.json"
BACK="$HOME/.openclaw/openclaw.json.backup-before-gpt4o-mini-$(date +%Y%m%d-%H%M%S)"
cp "$CFG" "$BACK"
node - <<'NODE'
const fs=require('fs');
const p=process.env.HOME+'/.openclaw/openclaw.json';
const c=JSON.parse(fs.readFileSync(p,'utf8'));
c.agents ??= {}; c.agents.defaults ??= {}; c.agents.defaults.model ??= {};
c.agents.defaults.model.primary = 'openai/gpt-4o-mini';
c.agents.defaults.model.fallbacks = ['openai/gpt-4o','openai/gpt-5-mini','openai-codex/gpt-5.4-mini'];
// Keep /model allowlist safe: ensure gpt-4o-mini and fallbacks exist, never clear this object.
c.agents.defaults.models ??= {};
for (const id of ['openai/gpt-4o-mini','openai/gpt-4o','openai/gpt-5-mini','openai-codex/gpt-5.4-mini']) c.agents.defaults.models[id] ??= {};
// Token control: cap output for OpenAI chat models and reduce runtime context for gpt-4o-mini.
const openai = c.models?.providers?.openai;
if (openai?.models) {
  for (const m of openai.models) {
    if (m.id === 'gpt-4o-mini') { m.maxTokens = 2048; m.contextTokens = 60000; }
    if (m.id === 'gpt-4o') { m.maxTokens = Math.min(m.maxTokens || 2048, 2048); m.contextTokens = Math.min(m.contextTokens || 80000, 80000); }
    if (m.id === 'gpt-5-mini') { m.maxTokens = Math.min(m.maxTokens || 2048, 2048); m.contextTokens = Math.min(m.contextTokens || 80000, 80000); }
  }
}
const codex = c.models?.providers?.['openai-codex'];
if (codex?.models) for (const m of codex.models) if (m.id === 'gpt-5.4-mini') { m.maxTokens = Math.min(m.maxTokens || 4096, 4096); m.contextTokens = Math.min(m.contextTokens || 120000, 120000); }
c.meta ??= {}; c.meta.lastTouchedAt = new Date().toISOString();
fs.writeFileSync(p, JSON.stringify(c,null,2)+'\n');
console.log('backup='+process.env.BACK);
NODE
openclaw config get agents.defaults.model
openclaw config get models.providers.openai.models | jq '.[] | select(.id=="gpt-4o-mini" or .id=="gpt-4o" or .id=="gpt-5-mini") | {id,maxTokens,contextTokens}'

node - <<'NODE'
const fs=require('fs'); const c=JSON.parse(fs.readFileSync(process.env.HOME+'/.openclaw/openclaw.json','utf8'));
console.log('default', c.agents.defaults.model);
for (const m of c.models.providers.openai.models.filter(m=>['gpt-4o-mini','gpt-4o','gpt-5-mini'].includes(m.id))) console.log(m.id,{maxTokens:m.maxTokens,contextTokens:m.contextTokens});
for (const m of c.models.providers['openai-codex'].models.filter(m=>m.id==='gpt-5.4-mini')) console.log('openai-codex/'+m.id,{maxTokens:m.maxTokens,contextTokens:m.contextTokens});
console.log('allowlist count', Object.keys(c.agents.defaults.models||{}).length, 'has4omini', !!c.agents.defaults.models['openai/gpt-4o-mini']);
NODE
journalctl --user -u openclaw-gateway -n 25 --no-pager | tail -25

